<section class="reviews">
    <div class="container">
        <div class="review-header">
            <div>
                <h2>Client perspectives</h2>
                <p>Thoughts from those who live with our objects.</p>
            </div>
            @auth
                @if(in_array(auth()->user()->role, ['admin', 'employee']))
                    {{-- Admin/employee admins do not review --}}
                @elseif($canReview)
                    <button class="btn btn-ghost" onclick="openReviewModal()">Share your perspective</button>
                @elseif($userReview)
                    <span class="btn btn-ghost" style="opacity:0.6; cursor:default;">Review submitted</span>
                @elseif(!$hasPurchased)
                    <span class="btn btn-ghost" style="opacity:0.6; cursor:default;" title="Only verified buyers can review">🔒 Write a review</span>
                @endif
            @else
                <a href="{{ route('login') }}" class="btn btn-ghost">Sign in to review</a>
            @endauth
        </div>

        <div class="review-list">
            @forelse($product->reviews as $review)
                <div class="review-item">
                    <div class="review-meta">
                        <div>
                            <span class="review-author">{{ $review->user->name }}</span>
                            {{-- Verified purchase badge --}}
                            @php
                                $reviewerPurchased = $review->user->orders()
                                    ->where('status', 'delivered')
                                    ->whereHas('items', fn($q) => $q->where('product_id', $review->product_id))
                                    ->exists();
                            @endphp
                            @if($reviewerPurchased)
                                <span class="verified-badge">Verified buyer</span>
                            @endif
                        </div>
                        <span class="review-date">{{ $review->created_at->format('M d, Y') }}</span>
                    </div>

