@push('scripts')
<script>
    const CSRF = document.querySelector('meta[name="csrf-token"]')?.content;


     function updateCartBadge(count){

        const badge = document.getElementById('cart-badge-count') ; 
        if(!badge) return ; 

        if(count > 0 ){

            badge.textContent = count ; 
            badge.classList.remove('hide') ; 
        }else{
            badge.classList.add('hide') ; 

        }
    }

    // Quantity selector
    function incrementQty() {
        let input = document.getElementById('quantity-input');
        let display = document.getElementById('quantity-display');
        let max = parseInt(input.max);
        let val = parseInt(input.value);
        if (val < max) {
            input.value = val + 1;
            display.textContent = val + 1;
        }
    }

    function decrementQty() {
        let input = document.getElementById('quantity-input');
        let display = document.getElementById('quantity-display');
        let val = parseInt(input.value);
        if (val > 1) {
            input.value = val - 1;
            display.textContent = val - 1;
        }
    }

    async function addToCart(btn) {
        if (btn.disabled) return;
        btn.disabled = true;
        const qty = parseInt(document.getElementById('quantity-input').value) || 1;
        const originalText = btn.textContent;

        try {
            const res = await fetch(btn.dataset.addUrl, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Accept': 'application/json',
                    'X-CSRF-TOKEN': CSRF,
                },
                body: JSON.stringify({ quantity: qty }),
            });
            const data = await res.json();
            if (data.success) {
                btn.textContent = 'Added to cart ✓';
                btn.style.background = 'var(--accent-sage)';
                btn.style.borderColor = 'var(--accent-sage)';
                
                // update nav badge
                updateCartBadge(data.cart_count);


                setTimeout(() => {
                    btn.textContent = originalText;
                    btn.style.background = '';
                    btn.style.borderColor = '';
                    btn.disabled = false;
                }, 2000);
            } else {
                btn.disabled = false;
            }
        } catch {
            btn.disabled = false;
        }
    }

    // Image gallery
    function changeMainImage(src) {
        document.querySelector('.main-image img').src = src;
    }

    // Image Zoom Effect
    const mainImageContainer = document.querySelector('.main-image');
    const zoomImage = mainImageContainer?.querySelector('img');

    if (mainImageContainer && zoomImage) {
        mainImageContainer.addEventListener('mousemove', (e) => {
            const { left, top, width, height } = mainImageContainer.getBoundingClientRect();
            const x = ((e.clientX - left) / width) * 100;
            const y = ((e.clientY - top) / height) * 100;
            zoomImage.style.transformOrigin = `${x}% ${y}%`;
        });

        mainImageContainer.addEventListener('mouseleave', () => {
            zoomImage.style.transformOrigin = 'center center';
        });
    }

    // Accordion
    function toggleAccordion(button) {
        const content = button.nextElementSibling;
        const icon = button.querySelector('i');
        const isOpen = content.style.maxHeight;

        document.querySelectorAll('.accordion-content').forEach(el => {
            el.style.maxHeight = null;
        });
        document.querySelectorAll('.accordion-header i').forEach(el => {
            el.style.transform = 'rotate(0deg)';
        });

        if (!isOpen) {
            content.style.maxHeight = content.scrollHeight + "px";
            icon.style.transform = 'rotate(180deg)';
            icon.style.transition = 'transform 0.3s ease';
        }
    }

    // Open first accordion by default
    document.addEventListener("DOMContentLoaded", () => {
        const firstButton = document.querySelector('.accordion-header');
        if(firstButton) toggleAccordion(firstButton);
    });

    // Review modal
    @auth
    function openReviewModal() {
        document.getElementById('reviewModal').style.display = 'flex';
    }
    function closeReviewModal() {
        document.getElementById('reviewModal').style.display = 'none';
    }
    
    // Toggle reply form
    function toggleReplyForm(id) {
        const form = document.getElementById(`reply-form-${id}`);
        form.style.display = form.style.display === 'none' ? 'block' : 'none';
    }
    @endauth
</script>
@endpush